### `app/blog/[id]/page.tsx`
Blog post page with dynamic params. Use `generateStaticParams` and `dynamicParams: true`.

```tsx
import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';

interface Post {
  id: number;
  title: string;
  body: string;
}

interface Comment {
  id: number;
  name: string;
  body: string;
  email: string;
}

interface PageProps {
  params: Promise<{ id: string }>;
}

async function getPost(id: string): Promise<Post> {
  const res = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
    next: { revalidate: 300 },
  });
  if (!res.ok) {
    throw new Error('Failed to fetch post');
  }
  return res.json();
}

async function getComments(id: string): Promise<Comment[]> {
  const res = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });
  if (!res.ok) {
    throw new Error('Failed to fetch comments');
  }
  return res.json();
}

export async function generateStaticParams() {
  const res = await fetch('https://jsonplaceholder.typicode.com/posts');
  const posts: Post[] = await res.json();

  return posts.slice(0, 10).map(post => ({
    id: post.id.toString(),
  }));
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { id } = await params;
  const post = await getPost(id);

  return {
    title: post.title,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

export const dynamicParams = true;

export default async function BlogPost({ params }: PageProps) {
  const { id } = await params;

  try {
    const [post, comments] = await Promise.all([
      getPost(id),
      getComments(id),
    ]);

    return (
      <article>
        <Link href="/blog">← Back</Link>

        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map(comment => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    );
  } catch {
    notFound();
  }
}
```

Wait, the previous code had `fallback: 'blocking'` which means if a page hasn't been generated yet, it will be server-rendered on the first request. With `dynamicParams: true`, this is the default behavior — any params not returned by `generateStaticParams` will be generated on-demand. So that's already covered.

